def parse_rust_f64(s):
    """Match Rust f64::from_str. Raises ValueError with appropriate message."""
    if not s:
        raise ValueError("cannot parse float from empty string")
    sl = s.lower()
    if sl in ("nan", "+nan", "-nan"):
        return float('nan')
    if sl in ("inf", "+inf", "infinity", "+infinity"):
        return float('inf')
    if sl in ("-inf", "-infinity"):
        return float('-inf')
    if '_' in s or 'x' in sl:
        raise ValueError("invalid float literal")
    try:
        return float(s)
    except ValueError:
        raise ValueError("invalid float literal")


def parse_u32(s):
    if not s:
        raise ValueError("cannot parse integer from empty string")
    if not s.isascii() or not s.isdigit():
        raise ValueError("invalid digit found in string")
    v = int(s)
    if v > 0xFFFFFFFF:
        raise ValueError("number too large to fit in target type")
    return v


