# ============================================================================
# Jaro-Winkler similarity (for clap "did you mean" suggestions)
# ============================================================================
def _jaro(s1, s2):
    if not s1 and not s2:
        return 1.0
    if not s1 or not s2:
        return 0.0
    l1, l2 = len(s1), len(s2)
    match_dist = max(l1, l2) // 2 - 1
    if match_dist < 0:
        match_dist = 0
    m1 = [False] * l1
    m2 = [False] * l2
    matches = 0
    for i in range(l1):
        start = max(0, i - match_dist)
        end = min(l2, i + match_dist + 1)
        for j in range(start, end):
            if m2[j] or s1[i] != s2[j]:
                continue
            m1[i] = True
            m2[j] = True
            matches += 1
            break
    if matches == 0:
        return 0.0
    t = 0
    k = 0
    for i in range(l1):
        if not m1[i]:
            continue
        while k < l2 and not m2[k]:
            k += 1
        if k < l2 and s1[i] != s2[k]:
            t += 1
        k += 1
    t //= 2
    return (matches / l1 + matches / l2 + (matches - t) / matches) / 3


def jaro_winkler(s1, s2):
    j = _jaro(s1, s2)
    p = 0.1
    l = 0
    for i in range(min(4, len(s1), len(s2))):
        if s1[i] == s2[i]:
            l += 1
        else:
            break
    return j + l * p * (1 - j)


def suggest_shell(input_val):
    best = None
    best_score = 0.0
    for s in SHELLS:
        score = jaro_winkler(s.lower(), input_val.lower())
        if score > best_score:
            best_score = score
            best = s
    if best_score >= 0.7:
        return best
    return None


